575	    fn handle_switch_statement(
576	        mut switch_stmt: Box<'a, SwitchStatement<'a>>,
577	        result: &mut Vec<'a, Statement<'a>>,
578	
579	        ctx: &mut TraverseCtx<'a>,
580	    ) {
581	        let changed = Self::substitute_single_use_symbol_in_statement(
582	            &mut switch_stmt.discriminant,
583	            result,
584	            ctx,
585	            false,
586	        );
587	        if changed {
588	            ctx.state.changed = true;
589	        }
590	
591	        if ctx.options().sequences
592	            && let Some(Statement::ExpressionStatement(prev_expr_stmt)) = result.last_mut()
593	        {
594	            let a = &mut prev_expr_stmt.expression;
595	            let b = &mut switch_stmt.discriminant;
596	            switch_stmt.discriminant = Self::join_sequence(a, b, ctx);
597	            result.pop();
598	            ctx.state.changed = true;
599	        }
600	
601	        // Prune empty case clauses before a trailing default
602	        // e.g., `switch (x) { case 0: foo(); break; case 1: default: bar() }`
603	        // => `switch (x) { case 0: foo(); break; default: bar() }`
604	        // https://github.com/evanw/esbuild/commit/add452ed51333953dd38a26f28a775bb220ea2e9
605	        if let Some(last_case) = switch_stmt.cases.last()
606	            && last_case.test.is_none()
607	        {
608	            let default_idx = switch_stmt.cases.len() - 1;
609	            let mut first_empty_idx = default_idx;
610	            // Iterate backward through preceding cases
611	            while first_empty_idx > 0 {
612	                let case = &switch_stmt.cases[first_empty_idx - 1];
613	                // Only remove empty cases with primitive literal tests
614	                if case.consequent.is_empty()
615	                    && case.test.as_ref().is_some_and(Expression::is_literal)
616	                {
617	                    first_empty_idx -= 1;
618	                } else {
619	                    break;
620	                }
621	            }
622	            // If we found cases to remove, keep cases [0..first_empty_idx] + [default]
623	            if first_empty_idx < default_idx {
624	                let default_case = switch_stmt.cases.pop().unwrap();
625	                switch_stmt.cases.truncate(first_empty_idx);
626	                switch_stmt.cases.push(default_case);
627	                ctx.state.changed = true;
628	            }
629	        }
630	
631	        result.push(Statement::SwitchStatement(switch_stmt));
632	    }
