634	    fn handle_if_statement(
635	        i: usize,
636	        stmts: &mut Vec<'a, Statement<'a>>,
637	        mut if_stmt: Box<'a, IfStatement<'a>>,
638	        result: &mut Vec<'a, Statement<'a>>,
639	
640	        ctx: &mut TraverseCtx<'a>,
641	    ) -> ControlFlow<()> {
642	        let changed =
643	            Self::substitute_single_use_symbol_in_statement(&mut if_stmt.test, result, ctx, false);
644	        if changed {
645	            ctx.state.changed = true;
646	        }
647	
648	        // Absorb a previous expression statement
649	        if ctx.options().sequences {
650	            if let Some(Statement::ExpressionStatement(prev_expr_stmt)) = result.last_mut() {
651	                let a = &mut prev_expr_stmt.expression;
652	                let b = &mut if_stmt.test;
653	                if_stmt.test = Self::join_sequence(a, b, ctx);
654	                result.pop();
655	                ctx.state.changed = true;
656	            }
657	
658	            if if_stmt.consequent.is_jump_statement() {
659	                // Absorb a previous if statement
660	                if let Some(Statement::IfStatement(prev_if_stmt)) = result.last_mut()
661	                    && prev_if_stmt.alternate.is_none()
662	                    && Self::jump_stmts_look_the_same(&prev_if_stmt.consequent, &if_stmt.consequent)
663	                {
664	                    // "if (a) break c; if (b) break c;" => "if (a || b) break c;"
665	                    // "if (a) continue c; if (b) continue c;" => "if (a || b) continue c;"
666	                    // "if (a) return c; if (b) return c;" => "if (a || b) return c;"
667	                    // "if (a) throw c; if (b) throw c;" => "if (a || b) throw c;"
668	                    if_stmt.test = Self::join_with_left_associative_op(
669	                        if_stmt.test.span(),
670	                        LogicalOperator::Or,
671	                        prev_if_stmt.test.take_in(ctx.ast),
672	                        if_stmt.test.take_in(ctx.ast),
673	                        ctx,
674	                    );
675	                    result.pop();
676	                    ctx.state.changed = true;
677	                }
678	
679	                let mut optimize_implicit_jump = false;
680	                // "while (x) { if (y) continue; z(); }" => "while (x) { if (!y) z(); }"
681	                // "while (x) { if (y) continue; else z(); w(); }" => "while (x) { if (!y) { z(); w(); } }" => "for (; x;) !y && (z(), w());"
682	                if ctx.ancestors().nth(1).is_some_and(|v| {
683	                    v.is_for_statement() || v.is_for_in_statement() || v.is_for_of_statement()
684	                }) && let Statement::ContinueStatement(continue_stmt) = &if_stmt.consequent
685	                    && continue_stmt.label.is_none()
686	                {
687	                    optimize_implicit_jump = true;
688	                }
689	
690	                // "let x = () => { if (y) return; z(); };" => "let x = () => { if (!y) z(); };"
691	                // "let x = () => { if (y) return; else z(); w(); };" => "let x = () => { if (!y) { z(); w(); } };" => "let x = () => { !y && (z(), w()); };"
692	                if ctx.parent().is_function_body()
693	                    && let Statement::ReturnStatement(return_stmt) = &if_stmt.consequent
694	                    && return_stmt.argument.is_none()
695	                {
696	                    optimize_implicit_jump = true;
697	                }
698	                if optimize_implicit_jump {
699	                    // Don't do this transformation if the branch condition could
700	                    // potentially access symbols declared later on on this scope below.
701	                    // If so, inverting the branch condition and nesting statements after
702	                    // this in a block would break that access which is a behavior change.
703	                    //
704	                    //   // This transformation is incorrect
705	                    //   if (a()) return; function a() {}
706	                    //   if (!a()) { function a() {} }
707	                    //
708	                    //   // This transformation is incorrect
709	                    //   if (a(() => b)) return; let b;
710	                    //   if (a(() => b)) { let b; }
711	                    //
712	                    let mut can_move_branch_condition_outside_scope = true;
713	                    if let Some(alternate) = &if_stmt.alternate
714	                        && Self::statement_cares_about_scope(alternate)
715	                    {
716	                        can_move_branch_condition_outside_scope = false;
717	                    }
718	                    if let Some(stmts) = stmts.get(i + 1..) {
719	                        for stmt in stmts {
720	                            if Self::statement_cares_about_scope(stmt) {
721	                                can_move_branch_condition_outside_scope = false;
722	                                break;
723	                            }
724	                        }
725	                    }
726	
727	                    if can_move_branch_condition_outside_scope {
728	                        let drained_stmts = stmts.drain(i + 1..);
729	                        let mut body = if let Some(alternate) = if_stmt.alternate.take() {
730	                            ctx.ast.vec_from_iter(iter::once(alternate).chain(drained_stmts))
731	                        } else {
732	                            ctx.ast.vec_from_iter(drained_stmts)
733	                        };
734	
735	                        Self::minimize_statements(&mut body, ctx);
736	                        let span = if body.is_empty() {
737	                            if_stmt.consequent.span()
738	                        } else {
739	                            body[0].span()
740	                        };
741	                        let test = if_stmt.test.take_in(ctx.ast);
742	                        let mut test = Self::minimize_not(test.span(), test, ctx);
743	                        Self::minimize_expression_in_boolean_context(&mut test, ctx);
744	                        let consequent = if body.len() == 1 {
745	                            body.remove(0)
746	                        } else {
747	                            let scope_id = ctx.create_child_scope_of_current(ScopeFlags::empty());
748	                            let block_stmt =
749	                                ctx.ast.block_statement_with_scope_id(span, body, scope_id);
750	                            Statement::BlockStatement(ctx.ast.alloc(block_stmt))
751	                        };
752	                        let mut if_stmt = ctx.ast.if_statement(test.span(), test, consequent, None);
753	                        let if_stmt = Self::try_minimize_if(&mut if_stmt, ctx)
754	                            .unwrap_or_else(|| Statement::IfStatement(ctx.ast.alloc(if_stmt)));
755	                        result.push(if_stmt);
756	                        ctx.state.changed = true;
757	                        return ControlFlow::Break(());
758	                    }
759	                }
760	
761	                if if_stmt.alternate.is_some() {
762	                    // "if (a) return b; else if (c) return d; else return e;" => "if (a) return b; if (c) return d; return e;"
763	                    result.push(Statement::IfStatement(if_stmt));
764	                    loop {
765	                        if let Some(Statement::IfStatement(if_stmt)) = result.last_mut()
766	                            && if_stmt.consequent.is_jump_statement()
767	                            && let Some(stmt) = if_stmt.alternate.take()
768	                        {
769	                            if let Statement::BlockStatement(block_stmt) = stmt {
770	                                Self::handle_block(result, block_stmt, ctx);
771	                            } else {
772	                                result.push(stmt);
773	                                ctx.state.changed = true;
774	                            }
775	                            continue;
776	                        }
777	                        break;
778	                    }
779	                    return ControlFlow::Continue(());
780	                }
781	            }
782	        }
783	
784	        result.push(Statement::IfStatement(if_stmt));
785	        ControlFlow::Continue(())
786	    }
