788	    fn handle_return_statement(
789	        mut ret_stmt: Box<'a, ReturnStatement<'a>>,
790	        result: &mut Vec<'a, Statement<'a>>,
791	        is_control_flow_dead: &mut bool,
792	
793	        ctx: &mut TraverseCtx<'a>,
794	    ) {
795	        if let Some(ret_argument_expr) = &mut ret_stmt.argument {
796	            let changed = Self::substitute_single_use_symbol_in_statement(
797	                ret_argument_expr,
798	                result,
799	                ctx,
800	                false,
801	            );
802	            if changed {
803	                ctx.state.changed = true;
804	            }
805	        }
806	
807	        if let Some(argument) = &mut ret_stmt.argument
808	            && argument.value_type(ctx) == ValueType::Undefined
809	            // `return undefined` has a different semantic in async generator function.
810	            && !ctx.is_closest_function_scope_an_async_generator()
811	        {
812	            ctx.state.changed = true;
813	            if argument.may_have_side_effects(ctx) {
814	                if ctx.options().sequences
815	                    && let Some(Statement::ExpressionStatement(prev_expr_stmt)) = result.last_mut()
816	                {
817	                    let a = &mut prev_expr_stmt.expression;
818	                    prev_expr_stmt.expression = Self::join_sequence(a, argument, ctx);
819	                } else {
820	                    result.push(
821	                        ctx.ast.statement_expression(argument.span(), argument.take_in(ctx.ast)),
822	                    );
823	                }
824	            }
825	            ret_stmt.argument = None;
826	            result.push(Statement::ReturnStatement(ret_stmt));
827	            *is_control_flow_dead = true;
828	            return;
829	        }
830	
831	        if ctx.options().sequences
832	            && let Some(Statement::ExpressionStatement(prev_expr_stmt)) = result.last_mut()
833	            && let Some(argument) = &mut ret_stmt.argument
834	        {
835	            let a = &mut prev_expr_stmt.expression;
836	            *argument = Self::join_sequence(a, argument, ctx);
837	            result.pop();
838	            ctx.state.changed = true;
839	        }
840	        result.push(Statement::ReturnStatement(ret_stmt));
841	        *is_control_flow_dead = true;
842	    }
