844	    fn handle_throw_statement(
845	        mut throw_stmt: Box<'a, ThrowStatement<'a>>,
846	        result: &mut Vec<'a, Statement<'a>>,
847	        is_control_flow_dead: &mut bool,
848	
849	        ctx: &mut TraverseCtx<'a>,
850	    ) {
851	        let changed = Self::substitute_single_use_symbol_in_statement(
852	            &mut throw_stmt.argument,
853	            result,
854	            ctx,
855	            false,
856	        );
857	        if changed {
858	            ctx.state.changed = true;
859	        }
860	
861	        if ctx.options().sequences
862	            && let Some(Statement::ExpressionStatement(prev_expr_stmt)) = result.last_mut()
863	        {
864	            let a = &mut prev_expr_stmt.expression;
865	            let b = &mut throw_stmt.argument;
866	            throw_stmt.argument = Self::join_sequence(a, b, ctx);
867	            result.pop();
868	            ctx.state.changed = true;
869	        }
870	        result.push(Statement::ThrowStatement(throw_stmt));
871	        *is_control_flow_dead = true;
872	    }
