874	    fn handle_for_statement(
875	        mut for_stmt: Box<'a, ForStatement<'a>>,
876	        result: &mut Vec<'a, Statement<'a>>,
877	
878	        ctx: &mut TraverseCtx<'a>,
879	    ) {
880	        if let Some(init) = &mut for_stmt.init {
881	            match init {
882	                ForStatementInit::VariableDeclaration(var_decl) => {
883	                    if let Some(first_decl) = var_decl.declarations.first_mut()
884	                        && let Some(first_decl_init) = first_decl.init.as_mut()
885	                    {
886	                        let is_block_scoped_decl = !first_decl.kind.is_var();
887	                        let changed = Self::substitute_single_use_symbol_in_statement(
888	                            first_decl_init,
889	                            result,
890	                            ctx,
891	                            is_block_scoped_decl,
892	                        );
893	                        if changed {
894	                            ctx.state.changed = true;
895	                        }
896	                    }
897	                    if Self::substitute_single_use_symbol_within_declaration(
898	                        var_decl.kind,
899	                        &mut var_decl.declarations,
900	                        ctx,
901	                    ) {
902	                        ctx.state.changed = true;
903	                    }
904	                }
905	                match_expression!(ForStatementInit) => {
906	                    let init = init.to_expression_mut();
907	                    let changed =
908	                        Self::substitute_single_use_symbol_in_statement(init, result, ctx, false);
909	                    if changed {
910	                        ctx.state.changed = true;
911	                    }
912	                }
913	            }
914	        }
915	
916	        if let Some(ForStatementInit::VariableDeclaration(var_decl)) = &mut for_stmt.init {
917	            let old_len = var_decl.declarations.len();
918	            var_decl.declarations.retain(|decl| {
919	                !Self::should_remove_unused_declarator(decl, ctx)
920	                    || decl.init.as_ref().is_some_and(|init| init.may_have_side_effects(ctx))
921	            });
922	            if old_len != var_decl.declarations.len() {
923	                if var_decl.declarations.is_empty() {
924	                    for_stmt.init = None;
925	                }
926	                ctx.state.changed = true;
927	            }
928	        }
929	
930	        if ctx.options().sequences {
931	            match result.last_mut() {
932	                Some(Statement::ExpressionStatement(prev_expr_stmt)) => {
933	                    if let Some(init) = &mut for_stmt.init {
934	                        if let Some(init) = init.as_expression_mut() {
935	                            let a = &mut prev_expr_stmt.expression;
936	                            *init = Self::join_sequence(a, init, ctx);
937	                            result.pop();
938	                            ctx.state.changed = true;
939	                        }
940	                    } else {
941	                        for_stmt.init = Some(ForStatementInit::from(
942	                            prev_expr_stmt.expression.take_in(ctx.ast),
943	                        ));
944	                        result.pop();
945	                        ctx.state.changed = true;
946	                    }
947	                }
948	                Some(Statement::VariableDeclaration(prev_var_decl)) => {
949	                    if let Some(init) = &mut for_stmt.init {
950	                        if prev_var_decl.kind.is_var()
951	                            && let ForStatementInit::VariableDeclaration(var_decl) = init
952	                            && var_decl.kind.is_var()
953	                        {
954	                            var_decl
955	                                .declarations
956	                                .splice(0..0, prev_var_decl.declarations.drain(..));
957	                            result.pop();
958	                            ctx.state.changed = true;
959	                        }
960	                    } else if prev_var_decl.kind.is_var() {
961	                        let Some(Statement::VariableDeclaration(prev_var_decl)) = result.pop()
962	                        else {
963	                            unreachable!()
964	                        };
965	                        for_stmt.init = Some(ForStatementInit::VariableDeclaration(prev_var_decl));
966	                        ctx.state.changed = true;
967	                    }
968	                }
969	                _ => {}
970	            }
971	        }
972	        result.push(Statement::ForStatement(for_stmt));
973	    }
974	
975	    fn handle_for_in_statement(
976	        mut for_in_stmt: Box<'a, ForInStatement<'a>>,
977	        result: &mut Vec<'a, Statement<'a>>,
978	
979	        ctx: &mut TraverseCtx<'a>,
980	    ) {
981	        // Annex B.3.5 allows initializers in non-strict mode
982	        // <https://tc39.es/ecma262/multipage/additional-ecmascript-features-for-web-browsers.html#sec-initializers-in-forin-statement-heads>
983	        // That is evaluated before the right hand side is evaluated. So, in that case, skip the single use substitution.
984	        if !matches!(&for_in_stmt.left, ForStatementLeft::VariableDeclaration(var_decl) if var_decl.has_init())
985	        {
986	            let is_block_scoped_decl = matches!(&for_in_stmt.left, ForStatementLeft::VariableDeclaration(var_decl) if !var_decl.kind.is_var());
987	            let changed = Self::substitute_single_use_symbol_in_statement(
988	                &mut for_in_stmt.right,
989	                result,
990	                ctx,
991	                is_block_scoped_decl,
992	            );
993	            if changed {
994	                ctx.state.changed = true;
995	            }
996	        }
997	
998	        if ctx.options().sequences {
999	            match result.last_mut() {
1000	                // "a; for (var b in c) d" => "for (var b in a, c) d"
1001	                Some(Statement::ExpressionStatement(prev_expr_stmt)) => {
1002	                    // Annex B.3.5 allows initializers in non-strict mode
1003	                    // <https://tc39.es/ecma262/multipage/additional-ecmascript-features-for-web-browsers.html#sec-initializers-in-forin-statement-heads>
1004	                    // If there's a side-effectful initializer, we should not move the previous statement inside.
1005	                    let has_side_effectful_initializer = {
1006	                        if let ForStatementLeft::VariableDeclaration(var_decl) = &for_in_stmt.left {
1007	                            if var_decl.declarations.len() == 1 {
1008	                                // only var can have a initializer
1009	                                var_decl.kind.is_var()
1010	                                    && var_decl.declarations[0]
1011	                                        .init
1012	                                        .as_ref()
1013	                                        .is_some_and(|init| init.may_have_side_effects(ctx))
1014	                            } else {
