1040	                            if prev_var_decl.kind.is_var()
1041	                                && prev_var_decl.declarations.len() == 1
1042	                                && prev_var_decl.declarations[0].init.is_none()
1043	                            {
1044	                                Some(&prev_var_decl.declarations[0])
1045	                            } else {
1046	                                None
1047	                            }
1048	                        };
