1069	    fn handle_for_of_statement(
1070	        mut for_of_stmt: Box<'a, ForOfStatement<'a>>,
1071	        result: &mut Vec<'a, Statement<'a>>,
1072	        ctx: &mut TraverseCtx<'a>,
1073	    ) {
1074	        let is_block_scoped_decl = matches!(&for_of_stmt.left, ForStatementLeft::VariableDeclaration(var_decl) if !var_decl.kind.is_var());
1075	        let changed = Self::substitute_single_use_symbol_in_statement(
1076	            &mut for_of_stmt.right,
1077	            result,
1078	            ctx,
1079	            is_block_scoped_decl,
1080	        );
1081	        if changed {
1082	            ctx.state.changed = true;
1083	        }
1084	
1085	        // "var a; for (a of b) c" => "for (var a of b) c"
1086	        if let Some(Statement::VariableDeclaration(prev_var_decl)) = result.last_mut()
1087	            && let ForStatementLeft::AssignmentTargetIdentifier(id) = &for_of_stmt.left
1088	        {
1089	            let prev_var_decl_no_init_item = {
1090	                if prev_var_decl.kind.is_var()
1091	                    && prev_var_decl.declarations.len() == 1
1092	                    && prev_var_decl.declarations[0].init.is_none()
1093	                {
1094	                    Some(&prev_var_decl.declarations[0])
1095	                } else {
1096	                    None
1097	                }
1098	            };
1099	            if let Some(prev_var_decl_item) = prev_var_decl_no_init_item
1100	                && let BindingPattern::BindingIdentifier(decl_id) = &prev_var_decl_item.id
1101	                && id.name == decl_id.name
1102	            {
1103	                let Some(Statement::VariableDeclaration(prev_var_decl)) = result.pop() else {
1104	                    unreachable!()
1105	                };
1106	                for_of_stmt.left = ForStatementLeft::VariableDeclaration(prev_var_decl);
1107	                ctx.state.changed = true;
1108	            }
1109	        }
1110	        result.push(Statement::ForOfStatement(for_of_stmt));
1111	    }
