1113	    /// `appendIfOrLabelBodyPreservingScope`: <https://github.com/evanw/esbuild/blob/v0.24.2/internal/js_ast/js_parser.go#L9852>
1114	    fn handle_block(
1115	        result: &mut Vec<'a, Statement<'a>>,
1116	        block_stmt: Box<'a, BlockStatement<'a>>,
1117	        ctx: &mut TraverseCtx<'a>,
1118	    ) {
1119	        let keep_block = block_stmt.body.iter().any(Self::statement_cares_about_scope);
1120	        if keep_block {
1121	            result.push(Statement::BlockStatement(block_stmt));
1122	        } else {
1123	            result.append(&mut block_stmt.unbox().body);
