1129	    pub fn statement_cares_about_scope(stmt: &Statement<'a>) -> bool {
1130	        match stmt {
1131	            Statement::BlockStatement(_)
1132	            | Statement::EmptyStatement(_)
1133	            | Statement::DebuggerStatement(_)
1134	            | Statement::ExpressionStatement(_)
1135	            | Statement::IfStatement(_)
1136	            | Statement::ForStatement(_)
1137	            | Statement::ForInStatement(_)
1138	            | Statement::ForOfStatement(_)
1139	            | Statement::DoWhileStatement(_)
1140	            | Statement::WhileStatement(_)
1141	            | Statement::WithStatement(_)
1142	            | Statement::TryStatement(_)
1143	            | Statement::SwitchStatement(_)
1144	            | Statement::ReturnStatement(_)
1145	            | Statement::ThrowStatement(_)
1146	            | Statement::BreakStatement(_)
1147	            | Statement::ContinueStatement(_)
1148	            | Statement::LabeledStatement(_) => false,
1149	            Statement::VariableDeclaration(decl) => !decl.kind.is_var(),
1150	            _ => true,
