1239	    /// Returns new length
1240	    fn substitute_single_use_symbol_in_expression_from_declarators(
1241	        target_expr: &mut Expression<'a>,
1242	        declarators: &mut [VariableDeclarator<'a>],
1243	        ctx: &TraverseCtx<'a>,
1244	        non_scoped_literal_only: bool,
1245	    ) -> usize {
1246	        let last_non_inlined_index = declarators.iter_mut().rposition(|prev_decl| {
1247	            let Some(prev_decl_init) = &mut prev_decl.init else {
1248	                return true;
1249	            };
1250	            let BindingPattern::BindingIdentifier(prev_decl_id) = &prev_decl.id else {
1251	                return true;
1252	            };
1253	            if ctx.is_expression_whose_name_needs_to_be_kept(prev_decl_init) {
1254	                return true;
1255	            }
1256	            let Some(symbol_value) =
1257	                ctx.state.symbol_values.get_symbol_value(prev_decl_id.symbol_id())
1258	            else {
1259	                return true;
1260	            };
1261	            // we should check whether it's exported by `symbol_value.exported`
1262	            // because the variable might be exported with `export { foo }` rather than `export var foo`
1263	            if symbol_value.exported
1264	                || symbol_value.read_references_count > 1
1265	                || symbol_value.write_references_count > 0
1266	            {
1267	                return true;
1268	            }
1269	            if non_scoped_literal_only && !prev_decl_init.is_literal_value(false, ctx) {
1270	                return true;
1271	            }
1272	            let replaced = Self::substitute_single_use_symbol_in_expression(
1273	                target_expr,
1274	                &prev_decl_id.name,
1275	                prev_decl_init,
1276	                prev_decl_init.may_have_side_effects(ctx),
1277	                ctx,
1278	            );
1279	            if replaced != Some(true) {
1280	                return true;
1281	            }
1282	            false
1283	        });
1284	        match last_non_inlined_index {
1285	            None => 0,
1286	            Some(last_non_inlined_index) => last_non_inlined_index + 1,
1287	        }
1288	    }
