1458	                // replacement past the left operand into the right operand.
1459	                if let Some(changed) = Self::substitute_single_use_symbol_in_expression(
1460	                    &mut assign_expr.right,
1461	                    search_for,
1462	                    replacement,
1463	                    replacement_has_side_effect,
1464	                    ctx,
1465	                ) {
1466	                    return Some(changed);
1467	                }
1468	            }
1469	            Expression::LogicalExpression(logical_expr) => {
1470	                if let Some(changed) = Self::substitute_single_use_symbol_in_expression(
1471	                    &mut logical_expr.left,
1472	                    search_for,
1473	                    replacement,
1474	                    replacement_has_side_effect,
1475	                    ctx,
1476	                ) {
1477	                    return Some(changed);
1478	                }
1479	                // Do not substitute our unconditionally-executed value into a branch
1480	                // unless the value itself has no side effects
1481	                if !replacement_has_side_effect
1482	                    && let Some(changed) = Self::substitute_single_use_symbol_in_expression(
1483	                        &mut logical_expr.right,
1484	                        search_for,
1485	                        replacement,
1486	                        replacement_has_side_effect,
1487	                        ctx,
1488	                    )
1489	                {
1490	                    return Some(changed);
1491	                }
1492	            }
1493	            Expression::PrivateInExpression(private_in_expr) => {
1494	                if let Some(changed) = Self::substitute_single_use_symbol_in_expression(
1495	                    &mut private_in_expr.right,
1496	                    search_for,
1497	                    replacement,
1498	                    replacement_has_side_effect,
1499	                    ctx,
1500	                ) {
1501	                    return Some(changed);
1502	                }
1503	            }
1504	            Expression::ConditionalExpression(cond_expr) => {
1505	                if let Some(changed) = Self::substitute_single_use_symbol_in_expression(
1506	                    &mut cond_expr.test,
1507	                    search_for,
1508	                    replacement,
1509	                    replacement_has_side_effect,
1510	                    ctx,
1511	                ) {
1512	                    return Some(changed);
