#[test]
fn test_inline_single_use_variable_in_object_with_string_key() {
    // Bug: variable inlining in object when string key is encountered
    // "test-a" string key before variable should not prevent inlining
    test(
        "
        var o = 'test-b', l = {
            'test-a': 'test-a',
            testb: o,
        };
        export { l };
        ",
        "
        var l = {
            'test-a': 'test-a',
            testb: 'test-b',
        };
        export { l };
        ",
    );
    // Without string key, it should work (already works)
    test(
        "
        var o = 'test-b', l = {
            testa: 'test-a',
            testb: o,
        };
        export { l };
        ",
        "
        var l = {
            testa: 'test-a',
            testb: 'test-b'
        };
        export { l };
        ",
    );
}

